module calculator(
  input clk,
  input reset,
  input [1:0] op,
  input [7:0] obf_a,
  input [7:0] b,
  output reg [7:0] result
);

  always @(posedge clk) begin
    if (reset) begin
      result <= 0;
    end else begin
      case (op)
        2'b00: result <= obf_a + b;
        2'b01: result <= obf_a - b;
        2'b10: result <= obf_a * b;
        2'b11: result <= obf_a / b;
      endcase
    end
  end

endmodule
